// Helper: map table name to its C++ type
inline auto& eas_type_map() {
  static std::map<std::string, std::string> m{
      {"Student", "Student"},
      {"Course", "Course"},
      {"Score", "Score"},
      {"Major", "Major"},
  };
  return m;
}

template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // We only support known EAS tables and matching types.
  const auto& tm = eas_type_map();
  auto it = tm.find(table_name);
  if (it == tm.end()) {
    throw std::runtime_error("Unsupported table name: " + table_name);
  }

  // Basic type-to-table consistency check at compile-time where possible.
  if constexpr (std::is_same_v<T, Student>) {
    if (table_name != "Student") {
      throw std::runtime_error("Type <Student> must be used with table \"Student\"");
    }
  } else if constexpr (std::is_same_v<T, Course>) {
    if (table_name != "Course") {
      throw std::runtime_error("Type <Course> must be used with table \"Course\"");
    }
  } else if constexpr (std::is_same_v<T, Score>) {
    if (table_name != "Score") {
      throw std::runtime_error("Type <Score> must be used with table \"Score\"");
    }
  } else if constexpr (std::is_same_v<T, Major>) {
    if (table_name != "Major") {
      throw std::runtime_error("Type <Major> must be used with table \"Major\"");
    }
  } else {
    throw std::runtime_error("Unsupported record type for EAS");
  }

  if (records.empty()) {
    return;
  }

  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        return sqlgen::insert(records).on(conn);
      })
      .value();
}

