namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  // Drop the Product table if it exists, then create it again.
  // Start a transaction, insert all products, and commit if everything succeeds.
  const auto result =
      sqlite::connect("test_db.sqlite")
          // Drop Product table if it exists
          .and_then(drop_table<Product> | if_exists)
          // Create Product table
          .and_then(create_table<Product>)
          // Begin transaction
          .and_then(begin_transaction)
          // Insert all products in a single batch
          .and_then(insert_range(products))
          // Commit the transaction
          .and_then(commit_transaction);

  // Return true if every step succeeded
  return result.has_value();
}

}  // namespace batch_insert_products
