```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  // Student table:
  // SNo      varchar(10) NOT NULL PRIMARY KEY
  // SName    varchar(30) NOT NULL
  // Sex      int NULL DEFAULT 1
  // Birthday datetime NULL
  // Major    int NULL
  // Scorses  float NULL DEFAULT 0
  // Remark   text NULL
  struct Student {
    // Primary key
    sqlgen::PrimaryKey<std::string> SNo;

    std::string                    SName;
    std::optional<int>             Sex;
    std::optional<std::string>     Birthday; // stored as TEXT / DATETIME
    std::optional<int>             Major;
    std::optional<double>          Scorses;
    std::optional<std::string>     Remark;
  };

  // Course table:
  // CID    int NOT NULL autoincrement PRIMARY KEY
  // CName  varchar(30) NOT NULL
  // Term   int NULL DEFAULT 1
  // CTime  int NULL
  // Credit float NOT NULL DEFAULT 0
  struct Course {
    sqlgen::PrimaryKey<int>        CID;   // AUTOINCREMENT INTEGER PRIMARY KEY
    std::string                    CName;
    std::optional<int>             Term;
    std::optional<int>             CTime;
    double                         Credit;
  };

  // Score table:
  // SNo   varchar(10) NOT NULL  (FK -> Student.SNo)
  // CID   int         NOT NULL  (FK -> Course.CID)
  // Score float NULL
  // PRIMARY KEY (SNo, CID)
  struct Score {
    std::string           SNo;
    int                   CID;
    std::optional<double> Score;
  };

  void design_eas_database() {
    // Path to SQLite database file
    const std::filesystem::path db_path{"test_db.sqlite"};

    // Open / create database
    auto db = sqlgen::sqlite::Database(db_path.string());

    // Create Student table
    {
      sqlgen::Table<Student> student_table("Student");
      auto create_sql = student_table.create_table_statement(db.dialect());

      // Append constraints to match the required schema
      create_sql +=
          ", PRIMARY KEY(\"SNo\")"
          ", CONSTRAINT \"ck_student_sex_default\" CHECK (Sex IS NULL OR Sex IN (0,1))";

      create_sql += ");";

      db.execute(create_sql);
    }

    // Create Course table
    {
      sqlgen::Table<Course> course_table("Course");
      auto create_sql = course_table.create_table_statement(db.dialect());

      // Make CID autoincrement primary key and enforce NOT NULL on Credit
      create_sql +=
          ", PRIMARY KEY(\"CID\" AUTOINCREMENT)"
          ", CONSTRAINT \"ck_course_credit_notnull\" CHECK (Credit IS NOT NULL)";

      create_sql += ");";

      db.execute(create_sql);
    }

    // Create Score table with composite primary key and foreign keys
    {
      sqlgen::Table<Score> score_table("Score");
      auto create_sql = score_table.create_table_statement(db.dialect());

      create_sql +=
          ", PRIMARY KEY(\"SNo\", \"CID\")"
          ", FOREIGN KEY(\"SNo\") REFERENCES \"Student\"(\"SNo\")"
          ", FOREIGN KEY(\"CID\") REFERENCES \"Course\"(\"CID\")";

      create_sql += ");";

      db.execute(create_sql);
    }
  }

}
