  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database "test_db.sqlite"
  auto conn = Connection{"test_db.sqlite"};

  // 2. Create User and Post tables (if not exist)
  conn.create_table<User>();
  conn.create_table<Post>();

  // 3. Create or replace the ActiveUser view that finds users with posts
