struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create Course and Enrollment tables if they do not exist
  const auto stats_result =
      conn
          .and_then(create_table<Course> | if_not_exists)
          .and_then(create_table<Enrollment> | if_not_exists)
          // Define and read from a view that computes the aggregated statistics
          .and_then(create_view<CourseStatsView, "course_stats_view">(
                        Course::title,
                        count(Enrollment::enrollment_id).as("student_count"_c),
                        avg(Enrollment::grade).as("avg_grade"_c)) |
                    if_not_exists |
                    from<Course> |
                    left_join<Enrollment>(Course::course_id == Enrollment::course_id) |
                    group_by(Course::course_id, Course::title))
          .and_then(sqlgen::read<std::vector<CourseStatsView>>);

  // If anything failed, return an empty vector
  if (!stats_result) {
    return {};
  }

  const auto &view_rows = stats_result.value();
  std::vector<CourseStats> result;
  result.reserve(view_rows.size());

  for (const auto &row : view_rows) {
    result.push_back(
        CourseStats{.title = row.title,
                    .student_count = row.student_count,
                    .avg_grade = row.avg_grade});
  }

  return result;
}

