namespace query_product_sales_report {

struct Product {
  static constexpr const char* tablename = "Product";

  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  static constexpr const char* tablename = "Sale";

  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* viewname = "ProductSalesReport";
  static constexpr bool is_view = true;

  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite connection to "test_db.sqlite"
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Build the view query:
  // SELECT p.category, SUM(s.quantity) AS total_qty, SUM(s.amount) AS total_amt
  // FROM Product p
  // INNER JOIN Sale s ON p.product_id = s.product_id
  // GROUP BY p.category
  // HAVING total_amt > 5000;
  const auto view_query =
      create_view_as<ProductSalesReport>(
          read<std::vector<ProductSalesReport>> |
          select("Product.category"_c,
                 sum("Sale.quantity"_c),
                 sum("Sale.amount"_c)) |
          from<Product, Sale>() |
          where("Product.product_id"_c == "Sale.product_id"_c) |
          group_by("Product.category"_c) |
          having(sum("Sale.amount"_c) > 5000));

  // Create (or replace) the view in SQLite
  sqlgen::sqlite::execute(conn, view_query);

  // Read from the view into a vector of ProductSalesReport
  const auto read_query = sqlgen::read<std::vector<ProductSalesReport>>();
  auto reports_from_view = sqlgen::sqlite::read(conn, read_query);

  // Convert to the desired return type CategoryReport
  std::vector<CategoryReport> result;
  result.reserve(reports_from_view.size());
  for (const auto& r : reports_from_view) {
    result.push_back(CategoryReport{
        .category = r.category,
        .total_qty = r.total_qty,
        .total_amt = r.total_amt,
    });
  }

  return result;
}

}  // namespace query_product_sales_report
