```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect explicitly to the given SQLite database file.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Start with base SELECT * FROM Book
  auto query = select_from<Book>();

  // Dynamically add WHERE clauses based on provided filters.
  if (filters.title_keyword) {
    // Use LIKE for partial title matching, wrap in '%' for contains search.
    std::string pattern = "%" + *filters.title_keyword + "%";
    query = std::move(query) |
            where("title"_c.like(std::move(pattern)));
  }

  if (filters.min_year) {
    query = std::move(query) |
            where("year"_c >= *filters.min_year);
  }

  if (filters.genre) {
    query = std::move(query) |
            where("genre"_c == *filters.genre);
  }

  if (filters.max_price) {
    query = std::move(query) |
            where("price"_c <= *filters.max_price);
  }

  // Execute the composed query and read back a vector of Book.
  return conn.and_then(std::move(query))
             .and_then(sqlgen::read<std::vector<Book>>);
}

}  // namespace query_search_books_by_criteria
