```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_complex_table {

struct UserProfile {
  // user_id INTEGER PRIMARY KEY AUTOINCREMENT
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;

  // username VARCHAR(50) NOT NULL UNIQUE
  // We use Unique<> + NotNull<> to express both constraints.
  sqlgen::NotNull<sqlgen::Unique<std::string>> username;

  // email VARCHAR(100) NOT NULL UNIQUE
  sqlgen::NotNull<sqlgen::Unique<std::string>> email;

  // age INTEGER CHECK(age >= 18)
  sqlgen::Check<int> age;

  // bio TEXT
  std::string bio;

  // created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  sqlgen::Default<sqlgen::DateTime> created_at;

  // is_verified BOOLEAN DEFAULT 0
  sqlgen::Default<bool> is_verified;
};

/**
 * Function: Create a table with various constraints and data types.
 * 
 * @return true if creation succeeds, false otherwise
 */
bool create_complex_table() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  if (!conn) {
    return false;
  }

  // Define the schema with constraints for the UserProfile table
  // and execute the CREATE TABLE command.
  //
  // We refine the generated schema to:
  // - set VARCHAR lengths for username (50) and email (100)
  // - add CHECK constraint on age: age >= 18
  // - set default CURRENT_TIMESTAMP for created_at
  // - set default 0 for is_verified
  auto result =
      conn.and_then([&](auto &c) {
            auto schema = make_schema<UserProfile>()
                              // username VARCHAR(50) NOT NULL UNIQUE
                              .column<&UserProfile::username>("username"_c)
                              .type(sql_type::varchar, 50)
                              .not_null()
                              .unique()
                              // email VARCHAR(100) NOT NULL UNIQUE
                              .column<&UserProfile::email>("email"_c)
                              .type(sql_type::varchar, 100)
                              .not_null()
                              .unique()
                              // age INTEGER CHECK(age >= 18)
                              .column<&UserProfile::age>("age"_c)
                              .type(sql_type::integer)
                              .check("age >= 18")
                              // bio TEXT
                              .column<&UserProfile::bio>("bio"_c)
                              .type(sql_type::text)
                              // created_at DATETIME DEFAULT CURRENT_TIMESTAMP
                              .column<&UserProfile::created_at>("created_at"_c)
                              .type(sql_type::datetime)
                              .default_expr("CURRENT_TIMESTAMP")
                              // is_verified BOOLEAN DEFAULT 0
                              .column<&UserProfile::is_verified>(
                                  "is_verified"_c)
                              .type(sql_type::boolean)
                              .default_value(0);

            return c.execute(create_table(schema) | if_not_exists);
          });

  return static_cast<bool>(result);
}

}  // namespace schema_create_complex_table
