 * - Call create_trigger_audit_log
 * - Update a record in Product
 * - Verify a corresponding record appears in AuditLog
 */
TEST(sqlite, create_trigger_audit_log) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Product>(conn);
  drop<AuditLog>(conn);
  exec(conn, "DROP TRIGGER IF EXISTS audit_product_update;");

  // 1. Create tables and trigger
  bool success = create_trigger_audit_log();
  EXPECT_TRUE(success);

  // 2. Insert initial data
  Product p1{.product_id = 1, .name = "Widget", .price = 10.0, .stock = 100};
  insert(conn, std::vector{p1});

  // 3. Update the record
  auto update_query = update<Product>("price"_c.set(12.5)) | where("product_id"_c == 1);
  auto update_res = update_query(conn);
  EXPECT_TRUE(update_res.has_value());

  // 4. Verify AuditLog
  auto logs = sqlgen::read<std::vector<AuditLog>>(conn).value();

  EXPECT_EQ(logs.size(), 1);
  EXPECT_EQ(logs[0].table_name, "Product");
  EXPECT_EQ(logs[0].record_id, 1);
  EXPECT_EQ(logs[0].action, "UPDATE");
  // Timestamp verification can be loose (just check it's not empty/null if possible, but here it's a struct field so it has value)
}

}  // namespace schema_create_trigger_audit_log

