namespace schema_create_trigger_audit_log {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct AuditLog {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> log_id;
  std::string table_name;
  int record_id;
  std::string action;
  sqlgen::DateTime timestamp;
};

/**
 * Function: Create a trigger for auditing changes on Product table.
 *
 * Connects to "test_db.sqlite", ensures Product and AuditLog tables exist,
 * then creates an AFTER UPDATE trigger on Product that inserts an entry
 * into AuditLog with action 'UPDATE' and CURRENT_TIMESTAMP.
 *
 * @return true if trigger creation succeeds, false otherwise
 */
bool create_trigger_audit_log() {
  using namespace sqlgen;

  // Connect explicitly to the SQLite database "test_db.sqlite"
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = std::move(*conn_result);

  // Ensure the Product and AuditLog tables exist.
  // (Assumption in description, but creating them is safe and idempotent.)
  conn = conn.and_then(create_table<Product> | if_not_exists);
  if (!conn) {
    return false;
  }

  conn = conn.and_then(create_table<AuditLog> | if_not_exists);
  if (!conn) {
    return false;
  }

  // Raw SQL for trigger creation.
  static constexpr const char* kTriggerSQL = R"SQL(
CREATE TRIGGER IF NOT EXISTS audit_product_update
AFTER UPDATE ON Product
BEGIN
    INSERT INTO AuditLog (table_name, record_id, action, timestamp)
    VALUES ('Product', OLD.product_id, 'UPDATE', CURRENT_TIMESTAMP);
END;
)SQL";

  // Execute the raw SQL using exec.
  conn = conn.and_then(exec(kTriggerSQL));
  if (!conn) {
    return false;
  }

  return true;
}

}  // namespace schema_create_trigger_audit_log
