```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  using namespace sqlgen;

  // Connect explicitly to the test_db.sqlite database
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = std::move(conn_result).value();

  // Helper lambda to check if an operation is either successful
  // or failed only because the column already exists.
  auto ok_or_column_exists = [](const auto& res) {
    if (res) {
      return true;
    }
    const auto& err = res.error();
    // SQLite reports "duplicate column name: <name>" when adding an existing column.
    // We treat that as non-fatal to make the migration idempotent.
    if (err.message.find("duplicate column name") != std::string::npos) {
      return true;
    }
    return false;
  };

  // Add phone_number column if it does not already exist
  auto res_phone =
      conn.execute("ALTER TABLE User ADD COLUMN phone_number VARCHAR(20);");
  if (!ok_or_column_exists(res_phone)) {
    return false;
  }

  // Add is_active column (stored as INTEGER with default 1 == true)
  auto res_active = conn.execute(
      "ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1;");
  if (!ok_or_column_exists(res_active)) {
    return false;
  }

  return true;
}

} // namespace schema_migration_add_column
