namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  // Nothing to delete
  if (ids.empty()) {
    return true;
  }

  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the specific SQLite database file "test_db.sqlite"
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = std::move(*conn_result);

  // Build a WHERE clause: doc_id IN (ids...)
  auto query =
      update<Document>()                              // UPDATE Document
      .set("is_deleted"_c = 1,                        // SET is_deleted = 1,
           "deleted_at"_c = CURRENT_TIMESTAMP)        //     deleted_at = CURRENT_TIMESTAMP
      .where(in("doc_id"_c, ids));                    // WHERE doc_id IN (ids...)

  // Execute the update
  auto result = conn.and_then(query);
  return result.has_value();
}

}  // namespace soft_delete_records
