```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;

  // Negative or zero transfers are not allowed.
  if (amount <= 0.0) {
    return false;
  }

  // Connect to the SQLite database "test_db.sqlite".
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto& conn = *conn_res;

  // Start a transaction.
  auto tx_res = begin_transaction(conn);
  if (!tx_res) {
    return false;
  }
  auto& tx = *tx_res;

  // Scope guard for rollback on any early return.
  bool committed = false;
  auto rollback_guard = [&]() {
    if (!committed) {
      (void)rollback(tx);
    }
  };

  // Check if the sender account exists and has sufficient balance.
  auto from_acc_res =
      select<Account>(tx)
          .where(column<&Account::account_id>() == from_account_id)
          .template read<std::optional<Account>>();
  if (!from_acc_res) {
    rollback_guard();
    return false;
  }
  auto from_acc_opt = *from_acc_res;
  if (!from_acc_opt.has_value()) {
    rollback_guard();
    return false;  // Sender account not found.
  }
  if (from_acc_opt->balance < amount) {
    rollback_guard();
    return false;  // Insufficient funds.
  }

  // Check that the receiver account exists.
  auto to_acc_res =
      select<Account>(tx)
          .where(column<&Account::account_id>() == to_account_id)
          .template read<std::optional<Account>>();
  if (!to_acc_res) {
    rollback_guard();
    return false;
  }
  auto to_acc_opt = *to_acc_res;
  if (!to_acc_opt.has_value()) {
    rollback_guard();
    return false;  // Receiver account not found.
  }

  // Deduct from the sender: balance = balance - amount.
  from_acc_opt->balance -= amount;
  auto upd_from_res = update(*from_acc_opt, tx);
  if (!upd_from_res) {
    rollback_guard();
    return false;
  }

  // Add to the receiver: balance = balance + amount.
  to_acc_opt->balance += amount;
  auto upd_to_res = update(*to_acc_opt, tx);
  if (!upd_to_res) {
    rollback_guard();
    return false;
  }

  // Commit the transaction.
  auto commit_res = commit(tx);
  if (!commit_res) {
    rollback_guard();
    return false;
  }

  committed = true;
  return true;
}

}  // namespace transaction_transfer_funds
