#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  // Ensure initial schema (including Major) exists
  design_eas_database_with_major();

  auto conn = sqlgen::sqlite::connect(db_path)
                  .and_then([](auto&& c) {
                    return sqlgen::exec(c, "PRAGMA foreign_keys = ON;")
                        .and_then([&c](auto&&) { return sqlgen::result(std::move(c)); });
                  })
                  .value();

  // 1. Add Grade column to Score: CHAR(1) NOT NULL
  sqlgen::exec(conn,
               "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT ' ';")
      .value();

  // 2. Modify Student.Age to INT NULL (SQLite requires table rebuild)
  // Only attempt if an Age column exists
  sqlgen::exec(conn,
               "CREATE TABLE IF NOT EXISTS Student_new ("
               "SNo VARCHAR(10) PRIMARY KEY NOT NULL,"
               "SName VARCHAR(30) NOT NULL,"
               "Sex INTEGER NOT NULL DEFAULT 1,"
               "Birthday DATETIME,"
               "Major INTEGER,"
               "Scorses REAL,"
               "Remark TEXT,"
               "Age INT"
               ");")
      .value();

  // Copy data from old Student (ignoring Age's old type; insert NULL)
  sqlgen::exec(conn,
               "INSERT INTO Student_new (SNo, SName, Sex, Birthday, Major, "
               "Scorses, Remark, Age) "
               "SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark, "
               "CAST(Age AS INT) "
               "FROM Student;")
      .value();

  sqlgen::exec(conn, "DROP TABLE Student;").value();
  sqlgen::exec(conn, "ALTER TABLE Student_new RENAME TO Student;").value();

  // 3. Drop Major table
  sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;").value();
}

} // namespace update_eas_table
