```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Build table object for Order
  auto orders = db.table<Order>("Order");

  // 1) Expire 'pending' orders older than 7 days
  //
  //   UPDATE "Order"
  //   SET status = 'expired'
  //   WHERE status = 'pending' AND order_date < DATE('now', '-7 days');
  //
  // Using sqlgen's expression API to generate the same logic.
  const auto expired_result = db.execute(
      update(orders)
          .set(orders(&Order::status) = "expired")
          .where(orders(&Order::status) == "pending" &&
                 // Use SQLite date function on the order_date column
                 func<sqlgen::Date>("DATE", orders(&Order::order_date)) <
                     func<sqlgen::Date>("DATE", "now", "-7 days")));

  int rows_affected = expired_result.rows_affected();

  // 2) Simulate delivery confirmation for shipped orders
  //
  //   UPDATE "Order"
  //   SET status = 'delivered'
  //   WHERE status = 'shipped';
  //
  const auto delivered_result = db.execute(
      update(orders)
          .set(orders(&Order::status) = "delivered")
          .where(orders(&Order::status) == "shipped"));

  rows_affected += delivered_result.rows_affected();

  // Return total number of rows affected by both updates
  return rows_affected;
}

} // namespace update_order_status
```

