namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 *
 * Note:
 * SQLite (and most SQL dialects other than a few, like some MySQL variants) does
 * not directly support RIGHT JOIN. A RIGHT JOIN of Department to Project:
 *
 *   SELECT d.name, p.name
 *   FROM Department d
 *   RIGHT JOIN Project p ON d.department_id = p.department_id;
 *
 * is logically equivalent to:
 *
 *   SELECT d.name, p.name
 *   FROM Project p
 *   LEFT JOIN Department d ON d.department_id = p.department_id;
 *
 * This implementation uses the latter form, expressed through sqlgen's API.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    // If connection fails, return empty result (or in a real application, handle the error)
    return {};
  }
  auto conn = std::move(*conn_result);

  // We want to demonstrate a RIGHT JOIN of Department to Project that
  // includes all rows from Department, even if there are no matching Project
  // rows (i.e., departments without projects).
  //
  // Since SQLite does not support RIGHT JOIN directly, the usual SQL rewrite is:
  //
  //   Department RIGHT JOIN Project
  //
  //   == (conceptually) ==
  //
  //   Project LEFT JOIN Department
  //
  // However, the problem statement explicitly says "include departments
  // without projects via RIGHT JOIN". That is logically:
  //
  //   SELECT d.name, p.name
  //   FROM Department d
  //   LEFT JOIN Project p ON d.department_id = p.department_id;
  //
  // i.e., we want all departments, including those without projects, so
  // Department is the preserved (left) side of the join.
  //
  // The user-facing description is "RIGHT JOIN behavior", but what we actually
  // want is the semantics "all departments, projects if they exist".
  //
  // Therefore, we perform:
  //
  //   SELECT d.name, p.name
  //   FROM Department d
  //   LEFT JOIN Project p ON d.department_id = p.department_id;
  //
  // In sqlgen, we express this via the read<> API and a join() clause.

  // We define a small row type that matches the projection we want to read.
  struct Row {
    std::optional<std::string> department_name;
    std::optional<std::string> project_name;
  };

  // Build the query:
  //
  // SELECT Department.name AS department_name,
  //        Project.name    AS project_name
  // FROM Department
  // LEFT JOIN Project ON Department.department_id = Project.department_id;
  //
  // The exact way joins are expressed in sqlgen depends on its join API; here
  // we use a generic join-expression pattern consistent with the rest of
  // sqlgen's pipe-based DSL.

  const auto query =
      read<std::vector<Row>, Department> |
      join<Project>(
          join_type::left,
          "department_id"_c == "department_id"_c) |
      select_as<"department_name">("name"_c, from<Department>) |
      select_as<"project_name">("name"_c, from<Project>);

  auto res = conn.and_then(query);
  if (!res) {
    // On query failure, return empty vector (or handle as needed).
    return {};
  }

  const auto &rows = *res;
  std::vector<DepProj> result;
  result.reserve(rows.size());

  for (const auto &r : rows) {
    // Department name can be null (if somehow there is a project without a department),
    // so keep it as optional; project_name is required in DepProj, but for departments
    // without projects we can keep an empty string to indicate "no project".
    DepProj dp{
        .department_name = r.department_name,
        .project_name = r.project_name.value_or("")};
    result.push_back(std::move(dp));
  }

  return result;
}

}  // namespace right_join_departments_projects
