```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>
#include <cassert>

namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Example connection (not actually used to run the query, only to show how
  // a typical flow could start). The function focuses on dry-run SQL generation.
  const auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build a complex query:
  //  - Join A and B on A.id = B.a_id
  //  - WHERE B.score > 10 AND A.name LIKE '%x%'
  //  - ORDER BY B.score DESC, A.name ASC
  //  - LIMIT 5
  //
  // read<std::vector<A>> uses table A as the "root" of the SELECT; columns from
  // B are included because of the join, but the result type here is just A,
  // which is fine for illustrating SQL generation.
  const auto query =
      sqlgen::read<std::vector<A>> |
      join<B>("id"_c == "a_id"_c) |
      where(("score"_c > 10.0) and ("name"_c like "%x%")) |
      order_by(desc("score"_c), "name"_c) |
      limit(5);

  // Generate SQL string for SQLite (dry run – no execution).
  const std::string sql = sqlgen::sqlite::to_sql(query);

  // Basic verification that the generated SQL contains expected clauses.
  // These checks are simple substring checks just to ensure the structure
  // roughly matches what we want for debugging purposes.
  assert(sql.find("SELECT") != std::string::npos);
  assert(sql.find("FROM \"A\"") != std::string::npos ||
         sql.find("FROM `A`") != std::string::npos);
  assert(sql.find("JOIN \"B\"") != std::string::npos ||
         sql.find("JOIN `B`") != std::string::npos);
  assert(sql.find("WHERE") != std::string::npos);
  assert(sql.find("score") != std::string::npos);
  assert(sql.find("name") != std::string::npos);
  assert(sql.find("ORDER BY") != std::string::npos);
  assert(sql.find("LIMIT 5") != std::string::npos);

  // Return the generated SQL string to the caller.
  return sql;
}

}  // namespace generate_sql_dry_run
