namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into the Event table in the SQLite database
 * "test_db.sqlite", runs a query to extract date/time parts and compute
 * duration, and returns the results as a vector of TemporalAnalysis.
 *
 * The function assumes that an `Event` table already exists in the database
 * with the appropriate schema.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the existing SQLite database.
  auto conn = sqlite::connect("test_db.sqlite");

  // Insert incoming events into the Event table.
  // If the table already contains rows, these will be additional records.
  if (!events.empty()) {
    const auto insert_query = Insert<Event>{}.into("Event") << values(events);
    sqlite::execute(conn, insert_query);
  }

  // Build the temporal analysis SELECT using SQLite date/time functions.
  //
  // Mapping of requested logical fields to SQLite:
  // - DAY        -> CAST(STRFTIME('%d', start_time) AS INTEGER)
  // - MONTH      -> CAST(STRFTIME('%m', start_time) AS INTEGER)
  // - YEAR       -> CAST(STRFTIME('%Y', start_time) AS INTEGER)
  // - HOUR       -> CAST(STRFTIME('%H', start_time) AS INTEGER)
  // - MINUTE     -> CAST(STRFTIME('%M', start_time) AS INTEGER)
  // - SECOND     -> CAST(STRFTIME('%S', start_time) AS INTEGER)
  // - WEEKDAY    -> CAST(STRFTIME('%w', start_time) AS INTEGER)
  // - UNIXEPOCH  -> CAST(STRFTIME('%s', start_time) AS INTEGER)
  // - DAYS_BETWEEN(start_time, end_time)
  //     -> JULIANDAY(end_time) - JULIANDAY(start_time)
  //
  // These are expressed via raw SQL snippets so sqlgen can project them
  // into our TemporalAnalysis struct.

  // Raw SQL snippet to compute the analysis columns.
  const char* analysis_sql =
      "SELECT "
      "  event_id AS event_id, "
      "  event_name AS event_name, "
      "  CAST(STRFTIME('%d', start_time) AS INTEGER) AS start_day, "
      "  CAST(STRFTIME('%m', start_time) AS INTEGER) AS start_month, "
      "  CAST(STRFTIME('%Y', start_time) AS INTEGER) AS start_year, "
      "  CAST(STRFTIME('%H', start_time) AS INTEGER) AS start_hour, "
      "  CAST(STRFTIME('%M', start_time) AS INTEGER) AS start_minute, "
      "  CAST(STRFTIME('%S', start_time) AS INTEGER) AS start_second, "
      "  CAST(STRFTIME('%w', start_time) AS INTEGER) AS start_weekday, "
      "  CAST(STRFTIME('%s', start_time) AS INTEGER) AS start_epoch, "
      "  CASE "
      "    WHEN end_time IS NOT NULL THEN "
      "      (JULIANDAY(end_time) - JULIANDAY(start_time)) "
      "    ELSE NULL "
      "  END AS duration_days "
      "FROM Event "
      "WHERE end_time IS NOT NULL;";

  // Execute the raw query and map each row into TemporalAnalysis.
  auto results = sqlite::query<TemporalAnalysis>(conn, analysis_sql);

  return results;
}

}  // namespace analyze_temporal_data
