```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  // Ensure the Inventory table exists (assumes schema with primary key)
  const auto table_result =
      conn_result.and_then(create_table<Inventory> | if_not_exists);
  if (!table_result) {
    return false;
  }

  // Upsert (insert or replace) the given inventory items
  const auto write_result = table_result.and_then(
      write(items, sqlite::write_mode::upsert));  // insert OR REPLACE
  if (!write_result) {
    return false;
  }

  // Read back all items from Inventory to verify the upsert
  const auto read_result =
      write_result.and_then(read<std::vector<Inventory>>);
  if (!read_result) {
    return false;
  }

  const auto& stored_items = *read_result;

  // Basic verification: ensure that for every input item there is exactly one
  // matching row in the database with the same values (upsert behavior).
  for (const auto& input_item : items) {
    int match_count = 0;
    for (const auto& db_item : stored_items) {
      if (db_item.item_id == input_item.item_id) {
        ++match_count;
        if (db_item.name != input_item.name ||
            db_item.quantity != input_item.quantity) {
          return false;
        }
      }
    }
    if (match_count != 1) {
      // Either missing or duplicated primary key after upsert
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
