```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <cmath>
#include <vector>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a temporary SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;

  // Connect to the specified SQLite database.
  const auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {};
  }
  auto conn = *conn_result;

  // Ensure the Product table exists. This uses sqlgen's automatic schema
  // generation based on the Product struct.
  {
    using namespace sqlgen::literals;
    const auto create_result = (create_table<Product> | if_not_exists)(conn);
    if (!create_result) {
      return {};
    }
  }

  // Insert provided products into the Product table.
  for (const auto& p : products) {
    const auto write_res = write(conn, p);
    if (!write_res) {
      // If any insert fails, stop and return what we have (or empty).
      return {};
    }
  }

  // Read all products and compute the mathematical analysis using
  // standard C++ <cmath> to mirror the intended SQL operations.
  std::vector<MathAnalysis> result;
  const auto read_res = read<std::vector<Product>>(conn);
  if (!read_res) {
    return {};
  }

  const auto& db_products = *read_res;
  result.reserve(db_products.size());

  for (const auto& p : db_products) {
    MathAnalysis m{};
    m.product_id = p.product_id.value;
    m.name = p.name;

    // Absolute, ceil, floor, and round (to 2 decimal places)
    m.abs_price = std::fabs(p.price);
    m.ceil_price = std::ceil(p.price);
    m.floor_price = std::floor(p.price);
    m.rounded_price = std::round(p.price * 100.0) / 100.0;

    // Exponential discount: exp(discount_rate / 100)
    m.exp_discount = std::exp(p.discount_rate / 100.0);

    // Natural log of price (ln). If price <= 0, produce NaN.
    if (p.price > 0.0) {
      m.ln_price = std::log(p.price);
    } else {
      m.ln_price = std::numeric_limits<double>::quiet_NaN();
    }

    // log2 of quantity (if quantity > 0, otherwise NaN).
    if (p.quantity > 0) {
      m.log2_quantity = std::log2(static_cast<double>(p.quantity));
    } else {
      m.log2_quantity = std::numeric_limits<double>::quiet_NaN();
    }

    // Trigonometric functions on discount_rate (treated as radians).
    m.sin_discount = std::sin(p.discount_rate);
    m.cos_discount = std::cos(p.discount_rate);
    m.tan_discount = std::tan(p.discount_rate);

    // Square root of quantity (if quantity >= 0).
    if (p.quantity >= 0) {
      m.sqrt_quantity = std::sqrt(static_cast<double>(p.quantity));
    } else {
      m.sqrt_quantity = std::numeric_limits<double>::quiet_NaN();
    }

    result.push_back(std::move(m));
  }

  return result;
}

}  // namespace mathematical_operations_analysis
