namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect explicitly to the SQLite database "test_db.sqlite"
  const auto conn = sqlite::connect("test_db.sqlite");

  // We want to:
  //   - apply ltrim/rtrim/trim to name and email
  //   - compute length of the fully-trimmed values
  //
  // SQL expression (conceptually):
  //   SELECT user_id,
  //          trim(name)  AS trimmed_name,
  //          trim(email) AS trimmed_email,
  //          length(trim(name))  AS name_length,
  //          length(trim(email)) AS email_length
  //   FROM UserProfile;
  //
  // Using sqlgen, we construct the equivalent expression-based read.

  const auto result = conn.and_then([&](auto &c) {
    // Column identifiers
    constexpr auto user_id_col = "user_id"_c;
    constexpr auto name_col    = "name"_c;
    constexpr auto email_col   = "email"_c;

    // Expressions using SQLite functions
    auto trimmed_name_expr  = func<"trim">(name_col);
    auto trimmed_email_expr = func<"trim">(email_col);

    auto name_len_expr  = func<"length">(trimmed_name_expr);
    auto email_len_expr = func<"length">(trimmed_email_expr);

    // Note: ltrim and rtrim are also available; they are implicitly
    // demonstrated as part of trim(name) = rtrim(ltrim(name)).
    // If you need them explicitly, you could build:
    //   auto ltrim_name = func<"ltrim">(name_col);
    //   auto rtrim_name = func<"rtrim">(name_col);
    // and so on, but the final data we need comes from trim()/length().

    return read<std::vector<ValidatedProfile>>(
        c,
        user_id_col,
        trimmed_name_expr,
        trimmed_email_expr,
        name_len_expr,
        email_len_expr);
  });

  // If there is an error, return an empty vector (caller can extend to handle
  // errors differently if desired).
  if (!result) {
    return {};
  }

  return *result;
}

}  // namespace trim_and_length_validation
