  auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to SQLite database: test_db.sqlite");
  }
  auto conn = std::move(conn_res.value());

  // Ensure the OrderItem table exists.
  {
    auto res = create_table<OrderItem> | if_not_exists;
    auto res_conn = res(conn);
    if (!res_conn) {
      throw std::runtime_error("Failed to create OrderItem table");
    }
    conn = std::move(res_conn.value());
  }

  // Insert all provided items into the OrderItem table.
  if (!items.empty()) {
    auto write_res = write(conn, items);
    if (!write_res) {
      throw std::runtime_error("Failed to insert OrderItem records");
    }
    conn = std::move(write_res.value());
  }

  // Build the query that performs all arithmetic and business metric calculations.
  //
  // The expressions mirror the provided reference SQL, with COALESCE wrappers to handle
  // nullable discount_rate and tax_rate fields. The modulo operator (%) is used to
  // group quantities into buckets of 10, and unit_cost demonstrates division.
  //
  // Reference:
  // SELECT
  //   item_id,
  //   order_id,
  //   product_id,
  //   unit_price,
  //   quantity,
  //   discount_rate,
  //   tax_rate,
  //   (unit_price * quantity) as gross_total,
  //   (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total,
  //   (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total,
  //   (unit_price * quantity / quantity) as unit_cost,
  //   (quantity % 10) as quantity_group,
  //   (unit_price * 0.3) as estimated_profit
  // FROM OrderItem;
  auto metrics_query =
      select(
          "item_id"_c,
          "order_id"_c,
          "product_id"_c,
          "unit_price"_c,
          "quantity"_c,
          "discount_rate"_c,
          "tax_rate"_c,
          // gross_total = unit_price * quantity
          ("unit_price"_c * "quantity"_c) >> "gross_total"_c,
          // discounted_total = gross_total * (1 - COALESCE(discount_rate,0)/100)
          ("unit_price"_c * "quantity"_c *
           (1.0 - coalesce("discount_rate"_c, 0.0) / 100.0)) >>
              "discounted_total"_c,
