          (("unit_price"_c * "quantity"_c) / "quantity"_c) >>
              "unit_cost"_c,
          // quantity_group = quantity % 10
          ("quantity"_c % 10) >> "quantity_group"_c,
          // estimated_profit = unit_price * 0.3 (simple example margin)
          ("unit_price"_c * 0.3) >> "estimated_profit"_c)
          .from<OrderItem>();

  auto rows_res = sqlgen::read<std::vector<detail::OrderMetricsRow>>(conn, metrics_query);
  if (!rows_res) {
    throw std::runtime_error("Failed to compute order metrics");
  }

  const auto& rows = rows_res.value();
  std::vector<OrderMetrics> result;
  result.reserve(rows.size());

  for (const auto& r : rows) {
    OrderMetrics m{
        .item_id = r.item_id,
        .order_id = r.order_id,
        .product_id = r.product_id,
        .unit_price = r.unit_price,
