/**
 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open connection to the SQLite database "test_db.sqlite"
  auto db = sqlite::Database{"test_db.sqlite"};

  // Build a SELECT with INNER JOINs and ORDER BY payment amount DESC.
  // We explicitly project the fields required by the Consolidated struct,
  // and alias Customer::name as "customer_name" to match the struct field.
  const auto query =
      Select{
          Order::order_id,
          Customer::name.as("customer_name"),
          Payment::amount}
          .from<Order>()
          .join<Customer>(Order::customer_id == Customer::customer_id)
          .join<Payment>(Order::order_id == Payment::order_id)
          .order_by(desc(Payment::amount));

  // Execute the query and map directly into Consolidated objects.
  auto result = sqlite::fetch_all<Consolidated>(db, query);

  return result;
}

}  // namespace join_orders_customers_payments
