  auto conn = conn_res.value();

  create_table<Note>(conn);

  const auto query =
      select_from<Note>(col<"note_id"> | as<"note_id">,
                        replace(col<"content">, "foo", "bar") |
                            as<"updated_content">) |
      to<std::vector<UpdatedNote>>;
  return query(conn).value();
}

