```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database file "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure foreign keys are enforced (required in SQLite)
  conn.execute("PRAGMA foreign_keys = ON;");

  // Drop tables if they exist to get a clean state
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Create Parent table
  conn.create_table<Parent>();

  // Create Child table with foreign key referencing Parent(parent_id)
  conn.create_table<Child>();

  // Insert a parent row
  Parent p{.parent_id = 1, .name = "parent-1"};
  conn.insert(p);

  // Insert a child row referencing that parent
  Child c{.child_id = 1, .parent_id = 1, .note = "child-of-parent-1"};
  conn.insert(c);

  // Delete the parent row; with ON DELETE CASCADE this should delete the child
  conn.remove<Parent>(p);

  // Verify whether any children remain for parent_id = 1
  auto remaining_children =
      conn.select<Child>().where(sqlgen::column<&Child::parent_id>() == 1);

  // If cascade works, there should be no remaining children
  return remaining_children.empty();
}

}  // namespace cascade_delete_demo
