#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace column_is_null_checks {

struct Profile {
  sqlgen::PrimaryKey<int> profile_id;
  std::string display_name;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

struct Result {
  int profile_id;
  std::string display_name;
};

std::vector<Result> column_is_null_checks() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the provided SQLite database file
  const auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Read profiles where some fields are NULL or NOT NULL.
  //
  // Example interpretation of "missing fields":
  //   - bio IS NULL  (missing bio)
  //   - avatar_url IS NOT NULL (has avatar)
  //
  // Adjust the condition as needed; here we show how to use both
  // IS NULL and IS NOT NULL in a where-clause.
  auto profiles =
      conn(sqlgen::read<std::vector<Profile>> |
           where("bio"_c.is_null() && "avatar_url"_c.is_not_null()));

  std::vector<Result> results;
  results.reserve(profiles.size());

  for (const auto& p : profiles) {
    results.push_back(Result{p.profile_id, p.display_name});
  }

  return results;
}

}  // namespace column_is_null_checks
