```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // 1. Create Account table (if it does not exist) and insert some test rows.
  const auto initial_accounts =
      std::vector<Account>{{Account{.account_id = 1, .balance = 100.0, .status = "active"},
                            Account{.account_id = 2, .balance = 200.0, .status = "active"},
                            Account{.account_id = 3, .balance = 0.0,   .status = "inactive"}}};

  const auto setup_result =
      conn.and_then(create_table<Account> | if_not_exists)
          .and_then(clear<Account>)  // ensure a clean slate
          .and_then(insert(initial_accounts));
  if (!setup_result) {
    return false;
  }

  // 2. Update balances and statuses using set(...)

  // Example 1: Increase balance by 50 for account_id = 1
  //   UPDATE Account SET balance = balance + 50 WHERE account_id = 1;
  const auto update_balance_result =
      conn.and_then(update<Account>
                    | set("balance"_c = "balance"_c + 50.0)
                    | where("account_id"_c == 1));
  if (!update_balance_result) {
    return false;
  }

  // Example 2: Mark accounts with balance > 150 as "preferred"
  //   UPDATE Account SET status = 'preferred' WHERE balance > 150;
  const auto update_status_result =
      conn.and_then(update<Account>
                    | set("status"_c = "preferred")
                    | where("balance"_c > 150.0));
  if (!update_status_result) {
    return false;
  }

  // Example 3: Set zero-balance accounts to "inactive"
  //   UPDATE Account SET status = 'inactive' WHERE balance = 0;
  const auto update_zero_balance_result =
      conn.and_then(update<Account>
                    | set("status"_c = "inactive")
                    | where("balance"_c == 0.0));
  if (!update_zero_balance_result) {
    return false;
  }

  // 3. Verify changes persisted by reading back from the table.
  const auto accounts_after_update = conn.and_then(read<std::vector<Account>>);
  if (!accounts_after_update) {
    return false;
  }

  const auto &accs = *accounts_after_update;
  if (accs.size() != 3) {
    return false;
  }

  // Helper lambda to find account by id.
  auto find_account = [&](int id) -> const Account * {
    for (const auto &a : accs) {
      if (a.account_id == id) {
        return &a;
      }
    }
    return nullptr;
  };

  const auto *a1 = find_account(1);
  const auto *a2 = find_account(2);
  const auto *a3 = find_account(3);

  if (!a1 || !a2 || !a3) {
    return false;
  }

  // Account 1: balance should be 150, status should be "preferred".
  if (a1->balance != 150.0 || a1->status != "preferred") {
    return false;
  }

  // Account 2: balance 200, status "preferred".
  if (a2->balance != 200.0 || a2->status != "preferred") {
    return false;
  }

  // Account 3: balance 0, status "inactive".
  if (a3->balance != 0.0 || a3->status != "inactive") {
    return false;
  }

  return true;
}

}  // namespace update_set_operations
```

