```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 *
 * This demonstrates a FULL OUTER JOIN between Supplier and Product using SQLite
 * (which does not support FULL JOIN natively) by performing a UNION of
 * LEFT JOIN and RIGHT JOIN (the latter emulated as LEFT JOIN with flipped tables).
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the specific SQLite database file.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Make sure the tables exist. This assumes the schema matches the structs.
  conn = conn.and_then(create_table<Supplier> | if_not_exists)
             .and_then(create_table<Product> | if_not_exists);

  // We cannot express FULL JOIN directly in SQLite, so we use a UNION of:
  // 1) Suppliers LEFT JOIN Products
  // 2) Suppliers RIGHT JOIN Products (emulated by Products LEFT JOIN Suppliers
  //    and filtering suppliers that are NULL on the joined side).
  //
  // For the second part we use COALESCE to always keep a supplier_name column,
  // and filter rows where the supplier side is NULL in the first join.
  const auto sql = R"SQL(
    SELECT
      s.name AS supplier_name,
      p.name AS product_name
    FROM Supplier s
    LEFT JOIN Product p
      ON s.supplier_id = p.supplier_id

    UNION

    SELECT
      COALESCE(s.name, '[no supplier]') AS supplier_name,
      p.name AS product_name
    FROM Product p
    LEFT JOIN Supplier s
      ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )SQL";

  std::vector<SupProd> result;

  conn.and_then([&](auto &c) {
        return c.execute(sql) |
               sqlgen::read<std::vector<SupProd>>;
      })
      .match(
          [&](const std::vector<SupProd> &rows) { result = rows; },
          [&](const auto &) {
            // On error, just return an empty result; in a real application you
            // might want to propagate or log the error instead.
            result.clear();
          });

  // Convert empty or placeholder product_name into std::nullopt if desired.
  for (auto &sp : result) {
    if (sp.product_name && sp.product_name->empty()) {
      sp.product_name = std::nullopt;
    }
  }

  return result;
}

}  // namespace full_join_suppliers_products
```

