namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the specified SQLite database.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure tables exist (schema inferred from structs).
  conn
      .and_then(create_table<Department> | if_not_exists)
      .and_then(create_table<Employee> | if_not_exists)
      .value();

  // Clear previous contents to make analysis deterministic.
  conn
      .and_then(exec("DELETE FROM Department;"))
      .and_then(exec("DELETE FROM Employee;"))
      .value();

  // Insert provided data.
  if (!depts.empty()) {
    conn.and_then(insert(depts)).value();
  }
  if (!emps.empty()) {
    conn.and_then(insert(emps)).value();
  }

  JoinAnalysis analysis;

  // Helper lambda to read a generic join result into JoinResult.
  auto fetch_join_results = [&](const std::string& sql) -> std::vector<JoinResult> {
    struct Row {
      std::optional<std::string> department_name;
      std::optional<std::string> first_name;
      std::optional<std::string> last_name;
      std::optional<double> salary;
    };

    const auto res =
        conn.and_then(query<Row>(sql)).value_or(std::vector<Row>{});

    std::vector<JoinResult> out;
    out.reserve(res.size());
    for (const auto& r : res) {
      out.push_back(JoinResult{
          .department_name = r.department_name,
          .first_name = r.first_name,
          .last_name = r.last_name,
          .salary = r.salary});
    }
    return out;
  };

  // INNER JOIN: employees with assigned departments.
  const std::string inner_join_sql =
      "SELECT d.department_name AS department_name, "
      "       e.first_name      AS first_name, "
      "       e.last_name       AS last_name, "
      "       e.salary          AS salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id;";

  analysis.inner_join_results = fetch_join_results(inner_join_sql);

  // LEFT JOIN: all employees (even without departments).
  const std::string left_join_sql =
      "SELECT d.department_name AS department_name, "
      "       e.first_name      AS first_name, "
      "       e.last_name       AS last_name, "
      "       e.salary          AS salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id;";

  analysis.left_join_results = fetch_join_results(left_join_sql);

  // RIGHT JOIN emulation (SQLite has no RIGHT JOIN):
  // RIGHT JOIN Department d ON e.department_id = d.department_id
  // == LEFT JOIN with swapped table order.
  const std::string right_join_sql =
      "SELECT d.department_name AS department_name, "
      "       e.first_name      AS first_name, "
      "       e.last_name       AS last_name, "
      "       e.salary          AS salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON e.department_id = d.department_id;";

  analysis.right_join_results = fetch_join_results(right_join_sql);

  // FULL OUTER JOIN emulation via UNION of left and right join variants.
  const std::string full_join_sql =
      "SELECT d.department_name AS department_name, "
      "       e.first_name      AS first_name, "
      "       e.last_name       AS last_name, "
      "       e.salary          AS salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name AS department_name, "
      "       e.first_name      AS first_name, "
      "       e.last_name       AS last_name, "
      "       e.salary          AS salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON e.department_id = d.department_id;";

  analysis.full_join_results = fetch_join_results(full_join_sql);

  return analysis;
}

}  // namespace analyze_department_employees
