```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::connect("test_db.sqlite");

  // Build and execute the query using sqlgen
  auto result = conn.and_then(
      select(
          Product::product_id,
          Product::product_name,
          Product::category,
          sum(Product::price * Sales::quantity).as<"total_sales">()) |
      from<Product, Sales>() |
      where(Product::product_id == Sales::product_id) |
      group_by(Product::product_id, Product::product_name, Product::category) |
      order_by(desc("total_sales"_c)) |
      limit(limit_count) |
      read<std::vector<TopProduct>>);

  // If the operation failed, return an empty vector.
  if (!result) {
    return {};
  }

  return *result;
}

}  // namespace get_top_products
