```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <unordered_map>

namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;
  auto conn = conn_res.value();

  // Ensure Product table exists (using sqlgen's create_table helper)
  {
    auto create_res = conn->exec(transpilation::to_create_table<Product>());
    if (!create_res) return false;
  }

  // Begin single transaction for all updates
  auto txn_res = begin_transaction(conn);
  if (!txn_res) return false;
  auto txn = txn_res.value();

  // Prepared statement for: UPDATE "Product" SET "stock" = "stock" + ? WHERE "product_id" = ?;
  auto update_stmt =
      update<Product>()
          .set("stock"_c = "stock"_c + parameter<int>())
          .where("product_id"_c == parameter<int>());

  for (const auto& [pid, qty] : received) {
    // Execute the update with bound parameters (quantity, product_id)
    auto exec_res = exec(txn, update_stmt, qty, pid);
    if (!exec_res) {
      // On any failure, rollback the whole transaction for atomicity
      auto _ = rollback(txn);
      return false;
    }
  }

  // Commit transaction if all updates succeeded
  auto commit_res = commit(txn);
  return commit_res.has_value();
}

}  // namespace update_inventory_stock
