```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace create_view_order_summary {

struct Order {
  static constexpr const char* tablename = "Order";

  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
};

struct OrderItem {
  static constexpr const char* tablename = "OrderItem";

  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  static constexpr const char* viewname = "OrderSummaryView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::Connection{"test_db.sqlite"};

  // Ensure the tables exist (idempotent; will not overwrite existing tables)
  conn.create_table_if_not_exists<Order>();
  conn.create_table_if_not_exists<OrderItem>();

  // Drop the view if it already exists, to make the function repeatable
  conn.execute(R"(DROP VIEW IF EXISTS OrderSummaryView;)");

  // Create the view using CREATE VIEW AS with the required aggregation
  conn.execute(R"(
    CREATE VIEW OrderSummaryView AS
    SELECT o.order_id,
           o.customer,
           SUM(oi.unit_price * oi.quantity) AS total
    FROM "Order" o
    INNER JOIN "OrderItem" oi
      ON o.order_id = oi.order_id
    GROUP BY o.order_id, o.customer;
  )");

  // Read from the view to verify and return the aggregated data
  return conn.select_from<OrderSummary>();
}

}  // namespace create_view_order_summary
