```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 *
 * Notes:
 * - Uses SQLite database "test_db.sqlite".
 * - Assumes a `Sales` table matching the `Sales` struct exists.
 * - Weekday is computed by SQLite's `strftime('%w', sale_time)`:
 *     0 = Sunday, 1 = Monday, ..., 6 = Saturday.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to the SQLite database.
  // The Credentials type in sqlgen::sqlite typically requires only the path.
  const auto credentials = Credentials{.path = std::string("test_db.sqlite")};
  auto conn = Connection{credentials};

  // Ensure the table exists (no-op if it already does).
  // This follows the patterns in the existing tests where CreateTable is used.
  const auto create_query = CreateTable<Sales>{};
  conn.execute(create_query);

  // We want: SELECT weekday, SUM(quantity) AS total_quantity
  //          FROM (SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday,
  //                       quantity
  //                FROM Sales)
  //          GROUP BY weekday
  //
  // sqlgen focuses on mapping tables/structs rather than arbitrary expressions,
  // so we execute a raw SQL query here and map the results manually.

  const std::string sql =
      "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
      "       SUM(quantity) AS total_quantity "
      "FROM Sales "
      "GROUP BY weekday "
      "ORDER BY weekday;";

  std::vector<WeekdayStats> result;
  result.reserve(7);

  conn.execute(sql, [&](int weekday, int total_quantity) {
    result.push_back(WeekdayStats{weekday, total_quantity});
  });

  return result;
}

}  // namespace weekday_sales_analysis
