```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::Connection{"test_db.sqlite"};

  // We use SQLite's strftime to extract time parts, and julianday() to compute day differences.
  // For weekly grouped metrics, we truncate the start_time to week (Mon-based week using '%W')
  // and group by project, year and week.
  //
  // Returned columns:
  //   project_id, name,
  //   day, month, year, hour, minute, second,
  //   duration_days (sum of per-log day difference within the week).
  const auto sql =
      R"SQL(
SELECT
  p.project_id AS project_id,
  p.name       AS name,
  CAST(strftime('%d', t.start_time) AS INTEGER) AS day,
  CAST(strftime('%m', t.start_time) AS INTEGER) AS month,
  CAST(strftime('%Y', t.start_time) AS INTEGER) AS year,
  CAST(strftime('%H', t.start_time) AS INTEGER) AS hour,
  CAST(strftime('%M', t.start_time) AS INTEGER) AS minute,
  CAST(strftime('%S', t.start_time) AS INTEGER) AS second,
  SUM(julianday(t.end_time) - julianday(t.start_time)) AS duration_days
FROM Project p
INNER JOIN TimeLog t
  ON p.project_id = t.project_id
GROUP BY
  p.project_id,
  p.name,
  year,
  strftime('%W', t.start_time),
  day,
  month,
  hour,
  minute,
  second
ORDER BY
  year,
  strftime('%W', t.start_time),
  p.project_id;
)SQL";

  // Define a lightweight row mapping struct matching the SELECT column order.
  struct Row {
    int project_id;
    std::string name;
    int day;
    int month;
    int year;
    int hour;
    int minute;
    int second;
    double duration_days;
  };

  // Execute the query and map results into Row, then populate TimeMetrics.
  const auto rows = sqlite::query<Row>(conn, sql);

  std::vector<TimeMetrics> result;
  result.reserve(rows.size());

  for (const auto& r : rows) {
    TimeMetrics tm;
    tm.project_id = r.project_id;
    tm.name = r.name;
    tm.day = r.day;
    tm.month = r.month;
    tm.year = r.year;
    tm.hour = r.hour;
    tm.minute = r.minute;
    tm.second = r.second;
    tm.duration_days = r.duration_days;
    result.emplace_back(std::move(tm));
  }

  return result;
}

}  // namespace project_time_tracking
