#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db{"test_db.sqlite"};

  // Build and execute a query that:
  // - Joins User and Post on user_id
  // - Groups by User.user_id and User.name
  // - Computes COUNT(Post.post_id) and AVG(length(Post.content))
  //
  // The selected columns are mapped to the Stats struct fields in order:
  //   user_id, name, post_count, avg_length
  auto result = db.select<Stats>(
      select(
          User::user_id,
          User::name,
          count(Post::post_id),
          avg(length(Post::content)))
          .from<User>()
          .join<Post>(User::user_id == Post::user_id)
          .group_by(User::user_id, User::name));

  return result;
}

}  // namespace group_by_with_aggregations
